package org.agmas.noellesroles.packet;
import net.minecraft.core.BlockPos; import net.minecraft.network.FriendlyByteBuf; import net.minecraft.network.RegistryFriendlyByteBuf; import net.minecraft.network.codec.StreamCodec; import net.minecraft.network.protocol.common.custom.CustomPacketPayload; import org.agmas.noellesroles.Noellesroles; import java.util.UUID;
public record CakeMakerBlockS2CPacket(UUID id, BlockPos pos, boolean cake, int bites, int ticks, boolean remove) implements CustomPacketPayload {
 public static final Type<CakeMakerBlockS2CPacket> ID=new Type<>(Noellesroles.id("cake_maker_block")); public static final StreamCodec<RegistryFriendlyByteBuf,CakeMakerBlockS2CPacket> CODEC=StreamCodec.ofMember(CakeMakerBlockS2CPacket::write,CakeMakerBlockS2CPacket::read); public Type<? extends CustomPacketPayload> type(){return ID;} public void write(FriendlyByteBuf b){b.writeUUID(id);b.writeBlockPos(pos);b.writeBoolean(cake);b.writeInt(bites);b.writeInt(ticks);b.writeBoolean(remove);} public static CakeMakerBlockS2CPacket read(FriendlyByteBuf b){return new CakeMakerBlockS2CPacket(b.readUUID(),b.readBlockPos(),b.readBoolean(),b.readInt(),b.readInt(),b.readBoolean());}
}
